import java.util.Scanner;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input using ESAPI
        String safeUserInput = ESAPI.encoder().encodeForHTML(userInput);

        // Output the sanitized input
        System.out.println("Hello, " + safeUserInput + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
